export class ESLint {
  constructor(options) {
    this.configFile = options.overrideConfigFile;
  }

  async isPathIgnored() {
    return false;
  }

  async calculateConfigForFile() {
    const module = await import(this.configFile);
    const rows = module.default ?? module;
    const merged = { plugins: {}, rules: {}, linterOptions: {} };
    for (const row of rows) {
      Object.assign(merged.plugins, row.plugins ?? {});
      Object.assign(merged.rules, row.rules ?? {});
      Object.assign(merged.linterOptions, row.linterOptions ?? {});
    }
    return merged;
  }
}
